package com.agent.quality.api.impl;  import com.agent.quality.api.ManualReviewQueue; import com.agent.quality.model.ManualReviewItem; import org.slf4j.Logger; import org.slf4j.LoggerFactory; import org.springframework.stereotype.Component;  import java.util.concurrent.ConcurrentLinkedQueue;  /**  * 人工审核队列实现 (doc 11-detail-flow F9, PRD §四(二)4).  *  * <p>骨架阶段策略：使用 {@link ConcurrentLinkedQueue} 在内存中维护待审核条目,  * push 入队尾, pop 从队头弹出 (FIFO)。生产实现应替换为 Redis / 消息队列。</p>  *  * <p>仅当 severityScore ≥ 0.8 的高严重度 Badcase 由编排层推送, 本实现不在此处  * 重复判定阈值 —— 仅负责队列存取。</p>  */ @Component public class ManualReviewQueueImpl implements ManualReviewQueue {      private static final Logger log = LoggerFactory.getLogger(ManualReviewQueueImpl.class);      /** 内存队列: ConcurrentLinkedQueue 提供非阻塞线程安全 FIFO. */     private final ConcurrentLinkedQueue<ManualReviewItem> queue = new ConcurrentLinkedQueue<>();      @Override     public void push(ManualReviewItem item) {         if (item == null) {             log.warn("人工审核队列收到空条目, 跳过");             return;         }         if (item.getBadcaseId() == null || item.getBadcaseId().isBlank()) {             log.warn("人工审核条目缺失 badcaseId, 仍入队 (审核员可按内容判定)");         }         if (item.getEnqueuedAt() == null) {             item.setEnqueuedAt(java.time.Instant.now());         }         queue.offer(item);         log.info("人工审核条目入队: badcaseId={}, severity={}", item.getBadcaseId(), item.getSeverity());     }      @Override     public ManualReviewItem pop() {         ManualReviewItem item = queue.poll();         if (item == null) {             log.debug("人工审核队列为空, pop 返回 null");         } else {             log.info("人工审核条目出队: badcaseId={}", item.getBadcaseId());         }         return item;     }      /** 当前队列深度, 供测试 / 监控使用. */     public int size() {         return queue.size();     }      /** 查看队头但不弹出, 返回 null 表示队列空. */     public ManualReviewItem peek() {         return queue.peek();     } }